using Antlr4.Runtime;
using Antlr4.Runtime.Atn;
using Antlr4.Runtime.Tree;
using Microsoft.Extensions.Logging;
using SolvasAm.Common.Extensions;
using SolvasAm.Common.Model.Expression;
using SolvasAm.DomainData.Ddx.Abstractions;
using SolvasAm.DomainData.Ddx.Listeners;
using SolvasAm.DomainData.Ddx.Utilities;
using SolvasAm.DomainData.Ddx.Visitors;
using SolvasAm.DomainData.Shared.Model.DataDictionary;
using System;
using System.Collections.Concurrent;
using System.Collections.Generic;
using System.Diagnostics;
using System.Linq;
using System.Linq.Expressions;

namespace SolvasAm.DomainData.Ddx
{
  public sealed class DdxTranslator : IDdxTranslator
  {
    private readonly IList<Field> _fields;
    private readonly IList<Common.Models.LookupItem> _fieldLookups;
    private readonly IList<Shared.Model.ReferenceData.FunctionDefinition> _functions;
    private readonly IEnumerable<string> _modelAssemblies;
    private static readonly ConcurrentDictionary<string, (int hash, IList<Common.Model.Expression.Rule> rules)> _ruleDefinitionsMap = new ConcurrentDictionary<string, (int, IList<SolvasAm.Common.Model.Expression.Rule>)>();
    private readonly IList<Common.Model.Expression.Rule> _ruleDefinitions;
    private readonly bool _maskQuotes;
    private readonly ILogger _logger;
    private readonly string _ownerId;
    private IList<DdxSyntaxError> _errors;

    private DdxTranslator(string ownerId, IList<Field> fields, IList<Common.Models.LookupItem> fieldLookups, IList<Shared.Model.ReferenceData.FunctionDefinition> functions, IList<Common.Model.Expression.Rule> ruleDefinitions, IEnumerable<string> modelAssemblies, ILogger logger = default, bool maskQuotes = false)
    {
      _ownerId = ownerId;
      _errors = new List<DdxSyntaxError>();
      _fields = fields;
      _fieldLookups = fieldLookups;
      _functions = functions;
      _modelAssemblies = modelAssemblies;
      _logger = logger;
      // The step below will translate the rule definitions to generate their friendly versions that will be required for further translations and rule expansions.
      // However, instead of doing this repeatedly each time an instance of the parser is created, we keep a concurrent dictionary of preprocessed rule definitions
      // so we can reuse if the incoming list of rule definitions are unchanged for a given owner.
      PreProcessRules(ruleDefinitions);
      _ruleDefinitions = _ruleDefinitionsMap[_ownerId].rules;
      _maskQuotes = maskQuotes;
    }

    private void PreProcessRules(IList<Rule> ruleDefinitions)
    {
      var sw = new Stopwatch();
      sw.Start();
      int currentHash = CalculateHashCodeForRules(ruleDefinitions);
      var shouldProcess = !_ruleDefinitionsMap.TryGetValue(_ownerId, out var rulesTuple) || (currentHash != rulesTuple.hash);

      if (shouldProcess)
      {
        _logger?.Trace("Preprocessing rules...");
        for (int i = 0; i < ruleDefinitions.Count; i++)
        {
          if (string.IsNullOrEmpty(ruleDefinitions[i].FriendlyDescription) && !string.IsNullOrEmpty(ruleDefinitions[i].Ddx) && TryTranslate(ruleDefinitions[i].Ddx, true, out string friendlyDdx))
            ruleDefinitions[i].FriendlyDescription = friendlyDdx;
        }
        _ruleDefinitionsMap.AddOrUpdate(_ownerId, (currentHash, ruleDefinitions), (_, __) => (currentHash, ruleDefinitions));
      }

      sw.Stop();
      _logger?.Debug($"Time taken to preprocess {ruleDefinitions.Count} rules in the translator is {sw.ElapsedMilliseconds} ms");
    }

    private static int CalculateHashCodeForRules(IEnumerable<SolvasAm.Common.Model.Expression.Rule> rules)
    {
      int hash = 17;
      foreach (var rule in rules)
      {
        hash = (hash * 23) + (rule.Ddx?.GetHashCode() ?? 0);
      }
      return hash;
    }

    public IEnumerable<DdxSyntaxError> Errors => _errors;

    public bool TryCreateExpressionFromFriendlyDdx(string friendlyDdx, DdxEvaluationTypeEnum? ddxEvalType, ParameterExpression paramExpr, out Expression expr)
    {
      return TryCreateExpression(friendlyDdx, paramExpr, out expr, ddxEvalType);
    }

    public bool TryTranslateToDynamicLinqExpression(string friendlyDdx, out string dlinqExpression)
    {
      _errors.Clear();
      dlinqExpression = null;
      var walker = new ParseTreeWalker();
      try
      {
        TryExpandRulesInFriendlyDdx(friendlyDdx, DdxEvaluationTypeEnum.BOOL, out var translated);
        TryTranslate(translated, false, out translated, true, DdxEvaluationTypeEnum.BOOL);
        // The friendly ddx has been translated now to ddx/sql. So, passing the encode flag as false so it can use sql dialect for parsing.
        var (parser, tokenStream) = GetParserAndTokenStream(translated, false);
        if (_errors.Count == 0)
        {
          var fieldTranslator = new DdxToDynamicLinqTranslator(tokenStream, _fields, _fieldLookups, _ruleDefinitions);
          var parseTree = parser.parse();
          //Validation error can short circuit the remaining processing.
          //Since the call below throws, additional errors related to replacing or walking the tree will not be captured.
          //which should be fine since the only relevant error in this case is the mismatch of types in value yielded by expression
          // vs the ddxEvaluationType passed in by the consumer.
          ValidateExpressionAgainstEvalulationType(DdxEvaluationTypeEnum.BOOL, parseTree);
          walker.Walk(fieldTranslator, parseTree);
          dlinqExpression = fieldTranslator.Rewriter.GetText();
        }
        dlinqExpression = DdxHelper.CleanseDdx(dlinqExpression);
        return _errors.Count == 0;
      }
      catch (Exception ex)
      {
        _errors.Add(new DdxSyntaxError(ex.Message));
        return false;
      }
    }

    public bool TryCreateExpressionFromDdx(string ddx, ParameterExpression paramExpr, out Expression expr)
    {
      if (TryTranslateToFriendlyDdx(ddx, true, out string friendlyDdx))
        return TryCreateExpression(friendlyDdx, paramExpr, out expr);
      expr = null;
      return false;
    }

    public bool TryTranslateToDdx(string friendlyDdx, DdxEvaluationTypeEnum? ddxEvalType, bool classicMode, out string ddx)
    {
      return TryTranslate(friendlyDdx, classicMode, out ddx, true, ddxEvalType);
    }

    public bool TryTranslateToFriendlyDdx(string ddx, bool classicMode, out string friendlyDdx)
    {
      return TryTranslate(ddx, classicMode, out friendlyDdx);
    }

    public bool TryExpandRulesInFriendlyDdx(string friendlyDdx, DdxEvaluationTypeEnum? ddxEvalType, out string expandedDdx)
    {
      _errors.Clear();
      expandedDdx = null;
      var (parser, tokenStream) = GetParserAndTokenStream(friendlyDdx, true);
      try
      {
        if (_errors.Count == 0)
        {
          var parseTree = parser.parse();
          ValidateExpressionAgainstEvalulationType(ddxEvalType, parseTree);
          var walker = new ParseTreeWalker();
          var ruleExpander = new DdxRuleTranslator(tokenStream, _ruleDefinitions);
          walker.Walk(ruleExpander, parseTree);
          expandedDdx = ruleExpander.Rewriter.GetText();
          expandedDdx = _maskQuotes ? DdxHelper.MaskQuotes(expandedDdx) : expandedDdx;
          return true;
        }
        return false;
      }
      catch (Exception ex)
      {
        _errors.Add(new DdxSyntaxError(ex.Message));
        return false;
      }
    }

    public bool TryTranslateToModelExpression(string friendlyDdx, DdxEvaluationTypeEnum? ddxEvalType, out SolvasAm.Common.GrpcApi.V1.ModelExpression modelExpression)
    {
      _errors.Clear();
      modelExpression = null;
      var eTreeVisitor = new DdxModelExpressionGenerator(_fields);
      var (parser, _) = GetParserAndTokenStream(friendlyDdx, true);
      try
      {
        if (_errors.Count == 0)
        {
          var parseTree = parser.parse();
          ValidateExpressionAgainstEvalulationType(ddxEvalType, parseTree);
          modelExpression = eTreeVisitor.Visit(parseTree);
          foreach (var line in modelExpression.Logic)
          {
            line.FriendlyDescription = _maskQuotes ? DdxHelper.MaskQuotes(line.FriendlyDescription) : line.FriendlyDescription;
            line.ComparisonValue = _maskQuotes ? DdxHelper.MaskQuotes(line.ComparisonValue) : line.ComparisonValue;
            line.ComparisonValue2 = _maskQuotes ? DdxHelper.MaskQuotes(line.ComparisonValue2) : line.ComparisonValue2;
          }
          return true;
        }
        return false;
      }
      catch (Exception ex)
      {
        _errors.Add(new DdxSyntaxError(ex.Message));
        return false;
      }
    }

    public bool TryListFieldsInDdx(string friendlyDdx, out IEnumerable<Field> fields)
    {
      _errors.Clear();
      fields = null;
      var (parser, _) = GetParserAndTokenStream(friendlyDdx, true);
      var walker = new ParseTreeWalker();
      try
      {
        if (_errors.Count == 0)
        {
          var parseTree = parser.parse();
          var fieldTranslator = new DdxFieldsExtractor(_fields);
          walker.Walk(fieldTranslator, parseTree);
          fields = fieldTranslator.DdxFields;
          return true;
        }
        return false;
      }
      catch (Exception ex)
      {
        _errors.Add(new DdxSyntaxError(ex.Message));
        return false;
      }
    }

    //public bool TryTranslateToModelExpressionMock(string ddx, out DdxModelExpression modelExpression)
    //{
    //  _errors.Clear();
    //  modelExpression = null;
    //  var eTreeVisitor = new MockDdxModelExpressionGenerator(_fields);
    //  var (parser, _) = GetParserAndTokenStream(ddx, true);
    //  var parseTree = parser.parse();
    //  try
    //  {
    //    modelExpression = eTreeVisitor.Visit(parseTree);
    //    return true;
    //  }
    //  catch (Exception ex)
    //  {
    //    _errors.Add(ex.Message);
    //    return false;
    //  }
    //}

    #region Private

    private bool TryCreateExpression(string text, ParameterExpression paramExpr, out Expression expr, DdxEvaluationTypeEnum? ddxEvalType = null)
    {
      _errors.Clear();
      expr = null;
      var eTreeVisitor = new DdxExpressionNodeGenerator(_fields, _fieldLookups, _ruleDefinitions, _modelAssemblies, paramExpr);
      var (parser, _) = GetParserAndTokenStream(text, true);

      try
      {
        if (_errors.Count == 0)
        {
          var parseTree = parser.parse();
          ValidateExpressionAgainstEvalulationType(ddxEvalType, parseTree);
          var exprNode = eTreeVisitor.Visit(parseTree);
          if (exprNode == null)
            return false;

          expr = exprNode.Expression;
          return true;
        }
        return false;
      }
      catch (Exception ex)
      {
        _errors.Add(new DdxSyntaxError(ex.Message));
        return false;
      }
    }

    private bool TryTranslate(string text, bool classicMode, out string translatedText, bool encode = false, DdxEvaluationTypeEnum? ddxEvalType = null)
    {
      _errors.Clear();
      translatedText = null;
      var walker = new ParseTreeWalker();

      if (encode)
      {
        try
        {
          // This is just an optimization. If the input expression matches the definition of a rule, just give back the ddx
          // of that rule since it has been already preprocessed.
          var matchingRule = _ruleDefinitions?.FirstOrDefault(x => x.FriendlyDescription == text);
          if (matchingRule != null)
          {
            _logger?.Debug("Found the rule in rule definitions. Skipping parser.");
            translatedText = DdxHelper.UnMaskQuotes(matchingRule.Ddx);
            return true;
          }
          var (parser, tokenStream) = GetParserAndTokenStream(text, encode);
          if (_errors.Count == 0)
          {
            var parseTree = parser.parse();
            //Validation error can short circuit the remaining processing.
            //Since the call below throws, additional errors related to replacing or walking the tree will not be captured.
            //which should be fine since the only relevant error in this case is the mismatch of types in value yielded by expression
            // vs the ddxEvaluationType passed in by the consumer.
            ValidateExpressionAgainstEvalulationType(ddxEvalType, parseTree);
          }
          var translated = ReplaceFields(walker, text, classicMode, encode);
          translated = ReplaceFieldLookups(walker, translated, encode);
          translated = ReplaceFunctions(walker, translated, encode);
          translated = TranslateStatement(walker, translated, classicMode, encode);
          translatedText = DdxHelper.UnMaskQuotes(translated);
          return _errors.Count == 0;
        }
        catch (Exception ex)
        {
          _errors.Add(new DdxSyntaxError(ex.Message));
          return false;
        }
      }
      else
      {
        try
        {
          // This is just an optimization. If the input expression matches the definition of a rule, just give back the friendly description
          // of that rule since it has been already preprocessed.
          var matchingRule = _ruleDefinitions?.FirstOrDefault(x => x.Ddx == text);
          if (matchingRule != null)
          {
            _logger?.Debug("Found the rule in rule definitions. Skipping parser.");
            translatedText = _maskQuotes ? DdxHelper.MaskQuotes(matchingRule.FriendlyDescription) : matchingRule.FriendlyDescription;
            return true;
          }

          var translated = ReplaceFunctions(walker, text, encode);
          translated = ReplaceFieldLookups(walker, translated, encode);
          translated = ReplaceFields(walker, translated, classicMode, encode);
          translated = TranslateStatement(walker, translated, classicMode, encode);
          translatedText = _maskQuotes ? DdxHelper.MaskQuotes(translated) : translated;
          return _errors.Count == 0;
        }
        catch (Exception ex)
        {
          _errors.Add(new DdxSyntaxError(ex.Message));
          return false;
        }
      }
    }

    private string ReplaceFields(ParseTreeWalker walker, string text, bool classicMode, bool encode)
    {
      var (parser, tokenStream) = GetParserAndTokenStream(text, encode);
      try
      {
        if (_errors.Count == 0)
        {
          IList<string> errors = null;
          var parseTree = parser.parse();
          var fieldMap = encode
            ? _fields.ToCodeDescriptionMap(e => classicMode && !string.IsNullOrEmpty(e.TableName) ? $"{e.TableName}.{e.Name}" : e.Name, e => e.DisplayName, out errors)
            : _fields.ToCodeDescriptionMap(e => e.DisplayName, e => e.Name, out errors);

          if (errors != null)
          {
            // We log these duplicate fields as warnings so we can continue to parse DDX statements that do not use these duplicates.
            // Unexpected results can be checked against the logs
            _logger?.Debug($"Mapping errors: {string.Join(", ", errors)}");
          }
          var fieldTranslator = new DdxFieldTranslator(tokenStream, fieldMap);
          walker.Walk(fieldTranslator, parseTree);
          return fieldTranslator.Rewriter.GetText();
        }
      }
      catch (Exception ex)
      {
        _errors.Add(new DdxSyntaxError(ex.Message));
      }
      return text;
    }

    private string ReplaceFieldLookups(ParseTreeWalker walker, string text, bool encode)
    {
      var (parser, tokenStream) = GetParserAndTokenStream(text, encode);
      try
      {
        if (_errors.Count == 0)
        {
          var parseTree = parser.parse();
          var fieldLookupMap = encode
            ? _fieldLookups.ToMapOfCodeDescriptionMap(e => e.ComposerLookupTypeCode, e => e.Code, e => e.Description, out var errors)
            : _fieldLookups.ToMapOfCodeDescriptionMap(e => e.ComposerLookupTypeCode, e => e.Description, e => e.Code, out errors);
          var fieldMap = _fields.ToDictionary(e => e.Name.ToLower(), e => e.LookupType);
          if (errors != null)
          {
            // We log these duplicate lookups as warnings so we can continue to parse DDX statements that do not use these duplicates.
            // Unexpected results can be checked against the logs
            _logger?.Debug($"Mapping errors: {string.Join(", ", errors)}");
          }

          var fieldLookupTranslator = new DdxFieldLookupTranslator(tokenStream, fieldLookupMap, _ruleDefinitions, fieldMap);
          walker.Walk(fieldLookupTranslator, parseTree);
          return fieldLookupTranslator.Rewriter.GetText();
        }
      }
      catch (Exception ex)
      {
        _errors.Add(new DdxSyntaxError(ex.Message));
      }
      return text;
    }

    private string ReplaceFunctions(ParseTreeWalker walker, string text, bool encode)
    {
      var (parser, tokenStream) = GetParserAndTokenStream(text, encode);
      try
      {
        if (_errors.Count == 0)
        {
          IList<string> errors = null;
          var parseTree = parser.parse();
          var functionMap = encode
            ? _functions.ToCodeDescriptionMap(e => e.Name, e => e.Description, out errors)
            : _functions.ToCodeDescriptionMap(e => e.Description, e => e.Name, out errors);

          if (errors != null)
          {
            // We log these duplicate functions as warnings so we can continue to parse DDX statements that do not use these duplicates.
            // Unexpected results can be checked against the logs
            _logger?.Debug($"Mapping errors: {string.Join(", ", errors)}");
          }

          var functionTranslator = new DdxFunctionTranslator(tokenStream, functionMap, encode);
          walker.Walk(functionTranslator, parseTree);
          return functionTranslator.Rewriter.GetText();
        }
      }
      catch (Exception ex)
      {
        _errors.Add(new DdxSyntaxError(ex.Message));
      }
      return text;
    }

    private string TranslateStatement(ParseTreeWalker walker, string text, bool classicMode, bool encode)
    {
      var (parser, tokenStream) = GetParserAndTokenStream(text, encode);
      try
      {
        if (_errors.Count == 0)
        {
          IList<string> errors = null;
          var parseTree = parser.parse();
          var fieldMap = encode
            ? _fields.ToCodeDescriptionMap(e => classicMode && !string.IsNullOrEmpty(e.TableName) ? $"{e.TableName}.{e.Name}" : e.Name, e => e.DisplayName, out errors)
            : _fields.ToCodeDescriptionMap(e => e.DisplayName, e => e.Name, out errors);

          if (errors != null)
          {
            // We log these duplicate fields as warnings so we can continue to parse DDX statements that do not use these duplicates.
            // Unexpected results can be checked against the logs
            _logger?.Debug($"Mapping errors: {string.Join(", ", errors)}");
          }

          DdxTranslatorBase translator;
          if (encode)
          {
            translator = new DdxSqlTranslator(tokenStream, classicMode, _fields);
          }
          else
          {
            translator = new SqlDdxTranslator(tokenStream, _fields);
          }
          walker.Walk(translator, parseTree);
          return translator.Rewriter.GetText();
        }
      }
      catch (Exception ex)
      {
        _errors.Add(new DdxSyntaxError(ex.Message));
      }
      return text;
    }

    private Tuple<DdxParser, CommonTokenStream> GetParserAndTokenStream(string ddxStr, bool isDecoded)
    {
      ddxStr = isDecoded ? DdxHelper.UnMaskQuotes(ddxStr) : DdxHelper.CleanseDdx(ddxStr);
      var ipStream = new AntlrInputStream(ddxStr);
      var lexer = new DdxLexer(ipStream) { dialect = isDecoded ? "ddx" : "sql" };
      var tokenStream = new CommonTokenStream(lexer);
      var parser = new DdxParser(tokenStream) { dialect = isDecoded ? "ddx" : "sql" };

      var ddxErrorListener = new DdxErrorListener();
      parser.RemoveErrorListeners();
      parser.AddErrorListener(ddxErrorListener);
      parser.Interpreter.PredictionMode = PredictionMode.LlExactAmbigDetection;

      //Since the parser and lexers are generated through multiple flows - for instance: translating to friendly, expanding rules, translating
      // to logic lines etc.. and they can call be called through a single DdxTranslator, this method gets called several times.
      //For the very first call, we want to set the _errors to point to the listener errors so later when parser.Parse is called, the errors get
      //populated. For later invocations, we don't want to remove any previously added custom errors.
      if (_errors.Count == 0)
      {
        _errors = ddxErrorListener.Errors;
      }
      else
      {
        foreach (var error in ddxErrorListener.Errors)
        {
          _errors.Add(error);
        }
      }

      return Tuple.Create(parser, tokenStream);
    }

    private void ValidateExpressionAgainstEvalulationType(DdxEvaluationTypeEnum? ddxEvalType, DdxParser.ParseContext parseTree)
    {
      //if the expression is ddx and is coming from the datastore
      if (!ddxEvalType.HasValue)
        return;

      var contextType = parseTree.Payload.GetChild(0).GetType();
      if (ddxEvalType.Value == DdxEvaluationTypeEnum.BOOL)
      {
        //Applicability expression
        if (contextType != typeof(DdxParser.ConditionContext))
          throw new Exception("Expression does not yield a true/false condition.");
      }
      else
      {
        //Formula
        if (contextType != typeof(DdxParser.ExpressionContext))
        {
          var functionContextType = parseTree.Payload.GetChild(0).GetChild(0).GetType();
          if (functionContextType != typeof(DdxParser.FCContext))
            throw new Exception("Expression does not yield a value.");
        }
      }
    }

    #endregion

    #region Builder
    public sealed class DdxTranslatorBuilder : IDdxFieldLookupAcceptor, IDdxFunctionDefinitionsAcceptor, IDdxRuleDefinitionsAcceptor, IDdxTranslatorBuilder
    {
      private readonly IList<Field> _fieldMap;
      private IList<SolvasAm.Common.Models.LookupItem> _fieldLookupMap;
      private IList<SolvasAm.DomainData.Shared.Model.ReferenceData.FunctionDefinition> _functions;
      private static DdxTranslatorBuilder Instance;
      private IEnumerable<string> _modelAssemblies;
      private IList<Rule> _ruleDefinitions;

      private DdxTranslatorBuilder(IList<Field> fieldMap)
      {
        _fieldMap = fieldMap;
      }

      public static IDdxFieldLookupAcceptor WithFields(IList<Field> fieldMap)
      {
        Instance = new DdxTranslatorBuilder(fieldMap);
        return Instance;
      }

      public IDdxFunctionDefinitionsAcceptor WithFieldLookups(IList<SolvasAm.Common.Models.LookupItem> fieldLookupMap)
      {
        Instance._fieldLookupMap = fieldLookupMap;
        return Instance;
      }

      public IDdxRuleDefinitionsAcceptor WithFunctionDefinitions(IList<SolvasAm.DomainData.Shared.Model.ReferenceData.FunctionDefinition> functions)
      {
        Instance._functions = functions;
        return Instance;
      }

      public IDdxTranslatorBuilder WithRuleDefinitions(IList<SolvasAm.Common.Model.Expression.Rule> ruleDefinitions)
      {
        Instance._ruleDefinitions = ruleDefinitions;
        return Instance;
      }

      public IDdxTranslatorBuilder WithLookupAssemblies(IEnumerable<string> modelAssemblies)
      {
        Instance._modelAssemblies = modelAssemblies;
        return Instance;
      }

      IDdxTranslator IDdxTranslatorBuilder.BuildForOwner(string ownerId, ILogger logger, bool maskQuotes)
      {
        return new DdxTranslator(ownerId, Instance._fieldMap, Instance._fieldLookupMap, Instance._functions, Instance._ruleDefinitions, Instance._modelAssemblies, logger, maskQuotes);
      }
    }

    #endregion
  }
}

