    [Flags]
    private enum ExpressionType { None = 0, Boolean = 1, Numeric = 2, Other = 4 }

    private ExpressionType ClassifyExpression(DdxParser.ExpressionContext expr)
    {
      var text = expr.GetText().Trim();

      // Strict boolean keywords
      if (string.Equals(text, "true", StringComparison.OrdinalIgnoreCase) ||
          string.Equals(text, "false", StringComparison.OrdinalIgnoreCase))
        return ExpressionType.Boolean;

      // Special case: 0/1 are both numeric and boolean
      if (text == "0" || text == "1")
        return ExpressionType.Boolean | ExpressionType.Numeric;

      // Numeric literals
      if (expr.literal() != null)
        return ExpressionType.Numeric;

      return ExpressionType.Other;
    }

