        if (searchedCase.else_expression() != null)
          resultExpressions.Add(searchedCase.else_expression().expression());
      }

      var simpleCase = caseExpr.simple_case_expression();
      if (simpleCase != null)
      {
        foreach (var sw in simpleCase.scalar_switch())
          resultExpressions.Add(sw.result_expression);
        if (simpleCase.else_expression() != null)
          resultExpressions.Add(simpleCase.else_expression().expression());
      }

      if (resultExpressions.Count == 0)
        return;

      var allBooleanOnly = resultExpressions.All(IsBooleanOnlyLiteral);

      if (ddxEvalType == DdxEvaluationTypeEnum.BOOL)
