        if (!allValidForBool)
          throw new Exception("Expression does not yield a true/false condition.");
      }
      else
      {
        // Value rejects: only when ALL results are strict boolean keywords (true/false)
        if (allBooleanOnly)
          throw new Exception("Expression does not yield a value.");
      }
    }

    private bool IsBooleanOnlyLiteral(DdxParser.ExpressionContext expr)
    {
      var text = expr.GetText().Trim();
      return string.Equals(text, "true", StringComparison.OrdinalIgnoreCase)
          || string.Equals(text, "false", StringComparison.OrdinalIgnoreCase);
    }

    private bool IsBooleanNumericLiteral(DdxParser.ExpressionContext expr)
    {
      var text = expr.GetText().Trim();
      return text == "0" || text == "1";
    }

