using Antlr4.Runtime.Misc;
using SolvasAm.Common.GrpcApi.V1;
using SolvasAm.DomainData.Ddx.Utilities;
using SolvasAm.DomainData.Shared.Model.DataDictionary;
using System.Collections.Generic;
using System.Linq;
using System.Text;

namespace SolvasAm.DomainData.Ddx.Visitors
{
  public class DdxModelExpressionGenerator : DdxBaseVisitor<ModelExpression>
  {
    private readonly ModelExpression modelExpression = new ModelExpression();
    private ModelExpressionLogic currentLogic;
    private string intermediateOperator;
    private readonly IDictionary<string, Field> _fieldMap;

    public DdxModelExpressionGenerator(IList<Field> fields)
    {
      _fieldMap = fields.Distinct(new DdxFieldDisplayNameComparer()).ToDictionary(f => f.DisplayName);
    }

    public override ModelExpression VisitCondition([NotNull] DdxParser.ConditionContext context)
    {
      if (context.SYM_LP() != null && context.SYM_RP() != null)
      {
        CreateNewLogicLine();
        currentLogic.OpenParenthesis++;
        //unwrap and visit inner condition
        Visit(context.condition(0));
        currentLogic.CloseParenthesis++;
        return null;
      }

      if (context.AND() != null)
      {
        //Every logical operator causes a new logic line. So let's create a new line for the left and the right.
        //The order of these statements matter since the logical operator and the parantheses if any are applied on the correct line
        CreateNewLogicLine();
        Visit(context.condition(0));
        CreateNewLogicLine(true);
        currentLogic.LogicalOperator = "AND";
        Visit(context.condition(1));
        return null;
      }
      if (context.OR() != null)
      {
        //Every logical operator causes a new logic line.
        //The order of these statements matter since the logical operator and the parantheses if any are applied on the correct line
        CreateNewLogicLine();
        Visit(context.condition(0));
        CreateNewLogicLine(true);
        currentLogic.LogicalOperator = "OR";
        Visit(context.condition(1));
        return null;
      }

      CreateNewLogicLine();

      if (context.NOT() != null)
      {
        //NOT can occur in combination with AND /OR.
        if (!string.IsNullOrEmpty(currentLogic.LogicalOperator))
          currentLogic.LogicalOperator = $"{currentLogic.LogicalOperator} NOT";
        else
          currentLogic.LogicalOperator = "NOT";
        Visit(context.condition(0));
        return null;
      }
      if (context.function_call() != null)
      {
        Visit(context.function_call());
        return null;
      }
      if (context.predicate() != null)
      {
        Visit(context.predicate());
        return null;
      }
      else
        return base.VisitCondition(context);
    }

    private void CreateNewLogicLine(bool force = false)
    {
      if (currentLogic == null || force)
      {
        currentLogic = new ModelExpressionLogic
        {
          LineNumber = modelExpression.Logic.Count
        };
        modelExpression.Logic.Add(currentLogic);
      }
    }

    public override ModelExpression VisitDdxPredicateEquals([NotNull] DdxParser.DdxPredicateEqualsContext context)
    {
      SetComparisonSegments(context.expression(0).GetText(), "=", context.expression(1).GetText());
      if (context.expression(0).field() != null)
        Visit(context.expression(0).field());
      return null;
    }

    public override ModelExpression VisitDdxPredicateIsNotEqualTo([NotNull] DdxParser.DdxPredicateIsNotEqualToContext context)
    {
      SetComparisonSegments(context.expression(0).GetText(), "<>", context.expression(1).GetText());
      if (context.expression(0).field() != null)
        Visit(context.expression(0).field());
      return null;
    }

    public override ModelExpression VisitDdxPredicateIsGreaterThan([NotNull] DdxParser.DdxPredicateIsGreaterThanContext context)
    {
      SetComparisonSegments(context.expression(0).GetText(), ">", context.expression(1).GetText());
      if (context.expression(0).field() != null)
        Visit(context.expression(0).field());
      return null;
    }

    public override ModelExpression VisitDdxPredicateIsGreaterThanOrEqual([NotNull] DdxParser.DdxPredicateIsGreaterThanOrEqualContext context)
    {
      SetComparisonSegments(context.expression(0).GetText(), ">=", context.expression(1).GetText());
      if (context.expression(0).field() != null)
        Visit(context.expression(0).field());
      return null;
    }

    public override ModelExpression VisitDdxPredicateIsLessThan([NotNull] DdxParser.DdxPredicateIsLessThanContext context)
    {
      SetComparisonSegments(context.expression(0).GetText(), "<", context.expression(1).GetText());
      if (context.expression(0).field() != null)
        Visit(context.expression(0).field());
      return null;
    }

    public override ModelExpression VisitDdxPredicateIsLessThanOrEqual([NotNull] DdxParser.DdxPredicateIsLessThanOrEqualContext context)
    {
      SetComparisonSegments(context.expression(0).GetText(), "<=", context.expression(1).GetText());
      if (context.expression(0).field() != null)
        Visit(context.expression(0).field());
      return null;
    }

    public override ModelExpression VisitDdxPredicateIsLike([NotNull] DdxParser.DdxPredicateIsLikeContext context)
    {
      SetComparisonSegments(context.expression(0).GetText(), "like", context.expression(1).GetText());
      if (context.expression(0).field() != null)
        Visit(context.expression(0).field());
      return null;
    }

    public override ModelExpression VisitDdxPredicateIsNotLike([NotNull] DdxParser.DdxPredicateIsNotLikeContext context)
    {
      SetComparisonSegments(context.expression(0).GetText(), "not like", context.expression(1).GetText());
      if (context.expression(0).field() != null)
        Visit(context.expression(0).field());
      return null;
    }

    public override ModelExpression VisitDdxPredicateIsBetween([NotNull] DdxParser.DdxPredicateIsBetweenContext context)
    {
      SetComparisonSegments(context.expression(0).GetText(), "between", context.expression(1).GetText(), context.expression(2).GetText());
      if (context.expression(0).field() != null)
        Visit(context.expression(0).field());
      return null;
    }

    public override ModelExpression VisitDdxPredicateIsNotBetween([NotNull] DdxParser.DdxPredicateIsNotBetweenContext context)
    {
      SetComparisonSegments(context.expression(0).GetText(), "not between", context.expression(1).GetText(), context.expression(2).GetText());
      if (context.expression(0).field() != null)
        Visit(context.expression(0).field());
      return null;
    }

    public override ModelExpression VisitDdxPredicateIsNotOneOf([NotNull] DdxParser.DdxPredicateIsNotOneOfContext context)
    {

      SetComparisonSegments(context.expression().GetText(), "not in", GetExpressionListText(context.expression_list()));
      if (context.expression().field() != null)
        Visit(context.expression().field());
      return null;
    }

    public override ModelExpression VisitDdxPredicateIsOneOf([NotNull] DdxParser.DdxPredicateIsOneOfContext context)
    {
      SetComparisonSegments(context.expression().GetText(), "in", GetExpressionListText(context.expression_list()));
      if (context.expression().field() != null)
        Visit(context.expression().field());
      return null;
    }

    public override ModelExpression VisitPredicateIsNull([NotNull] DdxParser.PredicateIsNullContext context)
    {
      SetComparisonSegments(context.expression().GetText(), "is null", null);
      if (context.expression().field() != null)
        Visit(context.expression().field());
      return null;
    }

    public override ModelExpression VisitPredicateIsNotNull([NotNull] DdxParser.PredicateIsNotNullContext context)
    {
      SetComparisonSegments(context.expression().GetText(), "is not null", null);
      if (context.expression().field() != null)
        Visit(context.expression().field());
      return null;
    }

    public override ModelExpression VisitDdxPredicatePassThroughCode([NotNull] DdxParser.DdxPredicatePassThroughCodeContext context)
    {
      currentLogic.ComparisonOperator = context.PASS_THROUGH_CODE().GetText();

      return base.VisitDdxPredicatePassThroughCode(context);
    }

    public override ModelExpression VisitPass_through_expression([NotNull] DdxParser.Pass_through_expressionContext context)
    {
      currentLogic.ComparisonValue = context.PASS_THROUGH_CODE().GetText();

      currentLogic.FriendlyDescription += $" {currentLogic.ComparisonValue}";

      return base.VisitPass_through_expression(context);
    }

    public override ModelExpression VisitField([NotNull] DdxParser.FieldContext context)
    {
      if (context.FIELD() != null)
      {
        var fieldName = context.FIELD().GetText();
        fieldName = fieldName.Trim('[', ']');
        if (_fieldMap.TryGetValue(fieldName, out var field))
        {
          currentLogic.FieldName = field.Name;
          currentLogic.DisplayName = field.DisplayName;
        }
      }
      return base.VisitField(context);
    }

    public override ModelExpression VisitFC([NotNull] DdxParser.FCContext context)
    {
      string parameters = context.expression_list() != null ? GetExpressionListText(context.expression_list()) : string.Empty;
      if (!string.IsNullOrEmpty(currentLogic.FriendlyDescription) && !string.IsNullOrEmpty(currentLogic.ComparisonOperator) && string.IsNullOrEmpty(intermediateOperator))
      {
        currentLogic.FriendlyDescription += $" {currentLogic.ComparisonOperator} {context.function_name().GetText()}({parameters})";

        return null;

      }

      currentLogic.FriendlyDescription += $"{context.function_name().GetText()}({parameters})";

      return null;
    }

    public override ModelExpression VisitParse([NotNull] DdxParser.ParseContext context)
    {
      if (context.condition() != null)
      {
        Visit(context.condition());
        return modelExpression;
      }
      return base.VisitParse(context);
    }

    private void SetComparisonSegments(string leftOperand, string comparisonOperator, string rightOperand, string rightOperand2 = null)
    {
      var friendlyOperator = DdxHelper.MapToFriendlyOperator(comparisonOperator);
      currentLogic.ComparisonOperator = friendlyOperator;
      currentLogic.ComparisonValue = rightOperand;
      if (!string.IsNullOrEmpty(rightOperand2))
      {
        currentLogic.ComparisonValue2 = rightOperand2;
        currentLogic.FriendlyDescription = $"{leftOperand} {friendlyOperator} {rightOperand} and {rightOperand2}";
      }
      else if (comparisonOperator.ToLower() == "in" || comparisonOperator.ToLower() == "not in")
      {
        currentLogic.FriendlyDescription = $"{leftOperand} {friendlyOperator} ({rightOperand})";
      }
      else if (comparisonOperator.ToLower() == "is null" || comparisonOperator.ToLower() == "is not null")
      {
        currentLogic.FriendlyDescription = $"{leftOperand} {friendlyOperator}";
      }
      else
      {
        currentLogic.FriendlyDescription = $"{leftOperand} {friendlyOperator} {rightOperand}";
      }
    }

    private string GetExpressionListText(DdxParser.Expression_listContext context)
    {
      var stb = new StringBuilder();
      foreach (var expr in context.expression())
      {
        if (expr.set() != null)
        {
          var setCtx = expr.set() as DdxParser.SETContext;
          stb.Append("{").Append(GetExpressionListText(setCtx.expression_list())).Append("}, ");
        }
        else
        {
          stb.Append($"{expr.GetText()}").Append(", ");
        }
      }
      return stb.ToString().TrimEnd(", ".ToCharArray());
    }

    public override ModelExpression VisitExpression([NotNull] DdxParser.ExpressionContext context)
    {
      if (context.SYM_AMPERSAND() != null)
      {
        Visit(context.expression(0));

        intermediateOperator = context.SYM_AMPERSAND().GetText();

        currentLogic.FriendlyDescription += $" {context.SYM_AMPERSAND().GetText()} ";

        Visit(context.expression(1));

        intermediateOperator = null;
        currentLogic.FriendlyDescription += $" {currentLogic.ComparisonOperator}";

        return null;
      }

      if (context.SYM_MINUS() != null)
      {
        Visit(context.expression(0));

        intermediateOperator = context.SYM_MINUS().GetText();

        currentLogic.FriendlyDescription += $" {context.SYM_MINUS().GetText()} ";

        Visit(context.expression(1));

        intermediateOperator = null;
        currentLogic.FriendlyDescription += $" {currentLogic.ComparisonOperator}";

        return null;

      }

      if (context.SYM_PLUS() != null)
      {
        Visit(context.expression(0));

        intermediateOperator = context.SYM_PLUS().GetText();

        currentLogic.FriendlyDescription += $" {context.SYM_PLUS().GetText()} ";

        Visit(context.expression(1));

        intermediateOperator = null;
        currentLogic.FriendlyDescription += $" {currentLogic.ComparisonOperator}";

        return null;
      }

      if (context.SYM_PIPE() != null)
      {
        Visit(context.expression(0));

        intermediateOperator = context.SYM_PIPE().GetText();

        currentLogic.FriendlyDescription += $" {context.SYM_PIPE().GetText()} ";


        Visit(context.expression(1));

        intermediateOperator = null;
        currentLogic.FriendlyDescription += $" {currentLogic.ComparisonOperator}";

        return null;
      }

      if (context.SYM_CARET() != null)
      {
        Visit(context.expression(0));

        intermediateOperator = context.SYM_CARET().GetText();

        currentLogic.FriendlyDescription += $" {context.SYM_CARET().GetText()} ";

        Visit(context.expression(1));

        intermediateOperator = null;
        currentLogic.FriendlyDescription += $" {currentLogic.ComparisonOperator}";

        return null;
      }
      if (context.SYM_SLASH() != null)
      {
        Visit(context.expression(0));

        intermediateOperator = context.SYM_SLASH().GetText();

        currentLogic.FriendlyDescription += $" {context.SYM_SLASH().GetText()} ";

        Visit(context.expression(1));

        intermediateOperator = null;
        currentLogic.FriendlyDescription += $" {currentLogic.ComparisonOperator}";

        return null;
      }

      if (context.SYM_ASTERISK() != null)
      {
        Visit(context.expression(0));

        intermediateOperator = context.SYM_ASTERISK().GetText();

        currentLogic.FriendlyDescription += $" {context.SYM_ASTERISK().GetText()} ";

        Visit(context.expression(1));

        intermediateOperator = null;
        currentLogic.FriendlyDescription += $" {currentLogic.ComparisonOperator}";

        return null;
      }

      if (context.literal() != null)
      {

        currentLogic.FriendlyDescription += $" {context.literal().GetText()} ";


        return null;
      }

      return base.VisitExpression(context);
    }

    public override ModelExpression VisitOdd_function_call([NotNull] DdxParser.Odd_function_callContext context)
    {
      var funcName = GetOddFunctionCall(context);
      string AppendWithSpace(string baseText, string toAppend)
          => string.IsNullOrWhiteSpace(baseText) ? toAppend : $"{baseText} {toAppend}";

      string ExprText(int index)
          => index >= 0 && index < context.expression().Length ? context.expression(index).GetText() : string.Empty;

      switch (funcName.ToUpperInvariant())
      {
        case "CONVERT":
        case "TRY_CONVERT":
          {
            var dataTypeText = context.data_type()?.GetText() ?? "<?>";
            var valueText = ExprText(0);

            var description = $"Convert({dataTypeText},{valueText})";

            currentLogic.FriendlyDescription = AppendWithSpace(currentLogic.FriendlyDescription, description);
            break;
          }

        case "CAST":
        case "TRY_CAST":
          {
            var valueText = ExprText(0);
            var dataTypeText = context.data_type()?.GetText() ?? "<?>";

            var description = $"Cast({dataTypeText}, {valueText})";
            currentLogic.FriendlyDescription = AppendWithSpace(currentLogic.FriendlyDescription, description);
            break;
          }

        case "PARSE":
        case "TRY_PARSE":
          {
            var valueText = ExprText(0);
            var dataTypeText = context.data_type()?.GetText() ?? "<?>";

            var description = $"Parse({dataTypeText}, {valueText})";

            currentLogic.FriendlyDescription = AppendWithSpace(currentLogic.FriendlyDescription, description);
            break;
          }

        case "IIF":
          {
            // IIF(condition, expression, expression)
            var condText = context.condition()?.GetText() ?? "<?>";
            var trueText = ExprText(0);
            var falseText = ExprText(1);

            var description = $"IIF( if {condText} then {trueText} else {falseText} )";
            currentLogic.FriendlyDescription = AppendWithSpace(currentLogic.FriendlyDescription, description);
            break;
          }

        case "DATEADD":
          {
            var datepartText = context.datepart()?.GetText() ?? "<?>";
            var numberText = ExprText(0);
            var dateText = ExprText(1);

            var description = $"DATEADD({datepartText}, {numberText}, {dateText})";
            currentLogic.FriendlyDescription = AppendWithSpace(currentLogic.FriendlyDescription, description);
            break;
          }

        case "DATEDIFF":
        case "DATEDIFF_BIG":
          {
            var datepartText = context.datepart()?.GetText() ?? "<?>";
            var startText = ExprText(0);
            var endText = ExprText(1);

            var description = $"{funcName}({datepartText}, {startText}, {endText})";
            currentLogic.FriendlyDescription = AppendWithSpace(currentLogic.FriendlyDescription, description);
            break;
          }

        case "DATENAME":
        case "DATEPART":
          {
            var datepartText = context.datepart()?.GetText() ?? "<?>";
            var dateText = ExprText(0);

            var description = $"{funcName}({datepartText}, {dateText})";
            currentLogic.FriendlyDescription = AppendWithSpace(currentLogic.FriendlyDescription, description);
            break;
          }

        default:
          {
            var rawText = context.GetText();
            currentLogic.FriendlyDescription = AppendWithSpace(currentLogic.FriendlyDescription, rawText);
            break;
          }
      }

      return null;
    }

    public string GetOddFunctionCall(DdxParser.Odd_function_callContext context)
    {
      if (context.CONVERT() != null) return context.CONVERT().GetText();
      if (context.TRY_CONVERT() != null) return context.TRY_CONVERT().GetText();
      if (context.CAST() != null) return context.CAST().GetText();
      if (context.TRY_CAST() != null) return context.TRY_CAST().GetText();
      if (context.PARSE() != null) return context.PARSE().GetText();
      if (context.TRY_PARSE() != null) return context.TRY_PARSE().GetText();
      if (context.IIF() != null) return context.IIF().GetText();
      if (context.DATEADD() != null) return context.DATEADD().GetText();
      if (context.DATEDIFF() != null) return context.DATEDIFF().GetText();
      if (context.DATEDIFF_BIG() != null) return context.DATEDIFF_BIG().GetText();
      if (context.DATENAME() != null) return context.DATENAME().GetText();
      if (context.DATEPART() != null) return context.DATEPART().GetText();

      return string.Empty;
    }

  }
